"use client";

import React, { useState } from 'react';
import { CRONOGRAMA_COMPLETO, CORES_MATERIAS } from "@/lib/constants";

export default function DashboardPage() {
  // Estado para controlar qual semana o aluno está a ver
  const [semanaAtual, setSemanaAtual] = useState(1);
  
  // Pegamos os dados da semana escolhida ou mostramos a semana 1 por padrão
  const dadosDaSemana = CRONOGRAMA_COMPLETO[semanaAtual] || CRONOGRAMA_COMPLETO[1];

  return (
    <div className="min-h-screen bg-gray-50 pb-12">
      {/* Header Premium */}
      <header className="bg-white border-b border-gray-200 px-4 py-8 mb-8">
        <div className="max-w-4xl mx-auto flex justify-between items-center">
          <div>
            <h1 className="text-3xl font-extrabold text-gray-900 tracking-tight">
              Enem<span className="text-blue-600">Focus</span>
            </h1>
            <p className="text-gray-500 mt-1 font-medium">Semana {semanaAtual} • Plano de Estudos</p>
          </div>

          {/* Navegação entre semanas */}
          <div className="flex gap-2">
            <button 
              onClick={() => setSemanaAtual(s => Math.max(1, s - 1))}
              className="p-2 bg-gray-100 hover:bg-gray-200 rounded-lg transition-colors text-gray-600"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 19l-7-7 7-7" /></svg>
            </button>
            <button 
              onClick={() => setSemanaAtual(s => s + 1)}
              className="px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-bold transition-all shadow-sm active:scale-95 text-sm"
            >
              Próxima Semana
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4">
        <div className="grid gap-8">
          {dadosDaSemana.map((item: any) => (
            <section key={item.dia} className="space-y-4">
              <div className="flex items-center gap-3">
                <div className="h-6 w-1 bg-blue-600 rounded-full"></div>
                <h2 className="text-lg font-bold text-gray-800">{item.dia}</h2>
              </div>

              <div className="grid gap-3">
                {item.tarefas.map((tarefa: any, idx: number) => (
                  <div 
                    key={idx} 
                    className="bg-white rounded-2xl p-4 border border-gray-200 shadow-sm hover:shadow-md transition-shadow"
                  >
                    <div className="flex items-center gap-4">
                      <input 
                        type="checkbox" 
                        className="w-6 h-6 rounded-lg border-gray-300 text-blue-600 focus:ring-blue-500"
                      />
                      <div>
                        <span className={`inline-block text-[10px] font-bold px-2 py-0.5 rounded-md border ${CORES_MATERIAS[tarefa.materia] || "bg-gray-100"}`}>
                          {tarefa.materia}
                        </span>
                        <h3 className="text-gray-900 font-semibold mt-1">{tarefa.tema}</h3>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </section>
          ))}
        </div>
      </main>
    </div>
  );
}